function AIChat() {
  const [messages, setMessages] = useState([
    {
      id: 1,
      role: 'ai',
      content: 'Hello! I\'m your AI assistant. How can I help you build your next application today?',
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [chatHistory, setChatHistory] = useState([
    { id: 1, title: 'New Chat', timestamp: new Date() }
  ]);
  const [activeChat, setActiveChat] = useState(1);
  const chatContainerRef = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [inputValue]);

  const quickSuggestions = [
    "Create a dashboard with charts and analytics",
    "Build an e-commerce store with payment integration",
    "Make a blog with CMS and user authentication",
    "Develop a real-time chat application",
    "Design a CRM system with customer management",
    "Generate a task management app with team collaboration"
  ];

  const handleSendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      role: 'user',
      content: inputValue,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsLoading(true);

    try {
      // Check if the user is asking to generate a project
      if (inputValue.toLowerCase().includes('generate') || 
          inputValue.toLowerCase().includes('create') || 
          inputValue.toLowerCase().includes('build')) {
        // Analyze the request and provide project generation options
        const analysisResponse = await aiChatService.analyzeRequirements(inputValue);
        
        const projectSuggestion = (
          <ProjectSuggestionCard>
            <ProjectSuggestionHeader>
              <Sparkles size={20} color="#0369a1" />
              <ProjectSuggestionTitle>Project Analysis</ProjectSuggestionTitle>
            </ProjectSuggestionHeader>
            
            <p>I can help you build "{inputValue}". Based on my analysis, here's what I recommend:</p>
            
            <ProjectDetailsGrid>
              <ProjectDetailItem>
                <ProjectDetailLabel>Project Type</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.analysis.project_type || 'Web Application'}</ProjectDetailValue>
              </ProjectDetailItem>
              
              <ProjectDetailItem>
                <ProjectDetailLabel>Estimated Time</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.estimated_time || '2-5 minutes'}</ProjectDetailValue>
              </ProjectDetailItem>
              
              <ProjectDetailItem>
                <ProjectDetailLabel>Complexity</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.analysis.complexity || 'Medium'}</ProjectDetailValue>
              </ProjectDetailItem>
            </ProjectDetailsGrid>
            
            <h4>Tech Stack Recommendation:</h4>
            <ProjectDetailsGrid>
              <ProjectDetailItem>
                <ProjectDetailLabel>Frontend</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.analysis.tech_recommendations?.frontend || 'React'}</ProjectDetailValue>
              </ProjectDetailItem>
              
              <ProjectDetailItem>
                <ProjectDetailLabel>Backend</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.analysis.tech_recommendations?.backend || 'FastAPI'}</ProjectDetailValue>
              </ProjectDetailItem>
              
              <ProjectDetailItem>
                <ProjectDetailLabel>Database</ProjectDetailLabel>
                <ProjectDetailValue>{analysisResponse.analysis.tech_recommendations?.database || 'MySQL'}</ProjectDetailValue>
              </ProjectDetailItem>
            </ProjectDetailsGrid>
            
            <h4>Key Features:</h4>
            <ul>
              {(analysisResponse.analysis.features || ['User Authentication', 'Responsive Design', 'API Integration']).map((feature, index) => (
                <li key={index}>{feature}</li>
              ))}
            </ul>
            
            <ProjectActionsContainer>
              <ProjectActionButton onClick={() => handleGenerateProject(inputValue)}>
                <Check size={16} />
                Generate Project
              </ProjectActionButton>
              <ProjectActionButton className="secondary" onClick={() => handleAskForModifications(analysisResponse)}>
                <Edit3 size={16} />
                Modify Requirements
              </ProjectActionButton>
            </ProjectActionsContainer>
          </ProjectSuggestionCard>
        );
        
        const aiResponse = {
          id: Date.now() + 1,
          role: 'ai',
          content: projectSuggestion,
          timestamp: new Date(),
          type: 'project_suggestion'
        };
        
        setMessages(prev => [...prev, aiResponse]);
        setIsLoading(false);
        return;
      }
      
      // Use the actual AI service for regular chat
      const response = await aiChatService.sendMessage(inputValue, {
        history: messages.slice(-5) // Send last 5 messages as context
      });
      
      const aiResponse = {
        id: Date.now() + 1,
        role: 'ai',
        content: response.response || 'I understand your request. How can I help you build your application?',
        timestamp: new Date()
      };
      
      setMessages(prev => [...prev, aiResponse]);
      setIsLoading(false);
    } catch (error) {
      console.error('Error sending message:', error);
      const errorMessage = {
        id: Date.now() + 1,
        role: 'ai',
        content: (
          <ErrorMessage>
            <AlertCircle size={20} />
            Sorry, I encountered an error processing your request. Please try again.
          </ErrorMessage>
        ),
        timestamp: new Date(),
        type: 'error'
      };
      setMessages(prev => [...prev, errorMessage]);
      setIsLoading(false);
    }
  };

  const handleAskForModifications = (analysisResponse) => {
    const modificationPrompt = `I'd like to modify the project requirements. Here's what I'd like to change:
    
1. Different tech stack preferences
2. Additional features
3. Specific design requirements

Please ask me questions to better understand my needs.`;
    
    setInputValue(modificationPrompt);
    textareaRef.current?.focus();
  };

  const handleGenerateProject = async (projectDescription) => {
    setIsLoading(true);
    
    try {
      // Show a success message
      const successMessage = {
        id: Date.now(),
        role: 'ai',
        content: (
          <SuccessMessage>
            <CheckCircle size={20} />
            Starting project generation for "{projectDescription}". This will take a few moments. You can check the progress in the Builder section.
          </SuccessMessage>
        ),
        timestamp: new Date(),
        type: 'success'
      };
      
      setMessages(prev => [...prev, successMessage]);
      
      // In a real implementation, this would navigate to the builder page
      // or trigger project generation directly
      console.log('Generating project:', projectDescription);
      
      // Simulate project generation
      setTimeout(() => {
        setIsLoading(false);
        // You could redirect to the builder page here
        // window.location.href = '/builder';
      }, 2000);
    } catch (error) {
      console.error('Error generating project:', error);
      const errorMessage = {
        id: Date.now() + 1,
        role: 'ai',
        content: (
          <ErrorMessage>
            <AlertCircle size={20} />
            Sorry, I encountered an error generating your project. Please try again.
          </ErrorMessage>
        ),
        timestamp: new Date(),
        type: 'error'
      };
      setMessages(prev => [...prev, errorMessage]);
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleNewChat = () => {
    const newChat = {
      id: Date.now(),
      title: 'New Chat',
      timestamp: new Date()
    };
    setChatHistory(prev => [newChat, ...prev]);
    setActiveChat(newChat.id);
    setMessages([
      {
        id: 1,
        role: 'ai',
        content: 'Hello! I\'m your AI assistant. How can I help you build your next application today?',
        timestamp: new Date()
      }
    ]);
  };

  const handleSuggestionClick = (suggestion) => {
    setInputValue(suggestion);
    textareaRef.current?.focus();
  };

  const handleCopyMessage = (content) => {
    // If content is a React element, we need to extract the text
    let textToCopy = content;
    if (typeof content === 'object' && content.props) {
      // This is a React element, extract text content
      textToCopy = content.props.children || '';
    }
    navigator.clipboard.writeText(textToCopy);
    // In a real implementation, you would show a toast notification
  };

  const handleLikeMessage = (messageId) => {
    // In a real implementation, you would send feedback to the backend
    console.log(`Message ${messageId} liked`);
  };

  const handleRegenerateResponse = async (messageId) => {
    // Find the last user message before this AI response
    const messageIndex = messages.findIndex(msg => msg.id === messageId);
    if (messageIndex > 0) {
      const userMessage = messages[messageIndex - 1];
      if (userMessage.role === 'user') {
        // Remove the current AI response and regenerate
        setMessages(prev => prev.slice(0, messageIndex));
        
        // Simulate typing delay
        setTimeout(() => {
          setIsLoading(true);
          
          // Use the actual AI service
          aiChatService.sendMessage(userMessage.content, {
            history: messages.slice(0, messageIndex - 1).slice(-5)
          }).then(response => {
            const aiResponse = {
              id: Date.now(),
              role: 'ai',
              content: response.response || 'I understand your request. How can I help you build your application?',
              timestamp: new Date()
            };
            setMessages(prev => [...prev, aiResponse]);
            setIsLoading(false);
          }).catch(error => {
            console.error('Error regenerating response:', error);
            const errorMessage = {
              id: Date.now(),
              role: 'ai',
              content: (
                <ErrorMessage>
                  <AlertCircle size={20} />
                  Sorry, I encountered an error regenerating the response. Please try again.
                </ErrorMessage>
              ),
              timestamp: new Date(),
              type: 'error'
            };
            setMessages(prev => [...prev, errorMessage]);
            setIsLoading(false);
          });
        }, 500);
      }
    }
  };

  const handleDislikeMessage = (messageId) => {
    // In a real implementation, you would send feedback to the backend
    console.log(`Message ${messageId} disliked`);
  };

  return (
    <Container>
      <Sidebar isOpen={sidebarOpen}>
        <SidebarHeader>
          <SidebarTitle>Chat History</SidebarTitle>
          <CloseButton onClick={() => setSidebarOpen(false)}>
            <X size={20} />
          </CloseButton>
        </SidebarHeader>
        
        <NewChatButton onClick={handleNewChat}>
          <Plus size={16} />
          New Chat
        </NewChatButton>
        
        <ChatHistory>
          {chatHistory.map(chat => (
            <ChatItem 
              key={chat.id} 
              className={chat.id === activeChat ? 'active' : ''}
              onClick={() => setActiveChat(chat.id)}
            >
              <MessageSquare size={16} />
              <span>{chat.title}</span>
            </ChatItem>
          ))}
        </ChatHistory>
      </Sidebar>
      
      <MainContent>
        <Header>
          <MenuButton onClick={() => setSidebarOpen(true)}>
            <Menu size={20} />
          </MenuButton>
          <div>
            <Title>
              <Bot size={24} />
              AI Chat Assistant
            </Title>
            <Subtitle>Ask me anything about building applications</Subtitle>
          </div>
        </Header>
        
        <ChatContainer ref={chatContainerRef}>
          {messages.map(message => (
            <Message key={message.id} role={message.role}>
              <Avatar className="avatar">
                {message.role === 'user' ? <User size={20} /> : <Bot size={20} />}
              </Avatar>
              <MessageContent>
                {typeof message.content === 'string' ? (
                  <div dangerouslySetInnerHTML={{ __html: message.content.replace(/\n/g, '<br />') }} />
                ) : (
                  message.content
                )}
                {message.role === 'ai' && (
                  <MessageActions>
                    <ActionButton onClick={() => handleCopyMessage(message.content)}>
                      <Copy size={14} />
                      Copy
                    </ActionButton>
                    <ActionButton onClick={() => handleLikeMessage(message.id)}>
                      <ThumbsUp size={14} />
                      Helpful
                    </ActionButton>
                    <ActionButton onClick={() => handleDislikeMessage(message.id)}>
                      <ThumbsDown size={14} />
                      Not Helpful
                    </ActionButton>
                    <ActionButton onClick={() => handleRegenerateResponse(message.id)}>
                      <RefreshCw size={14} />
                      Regenerate
                    </ActionButton>
                  </MessageActions>
                )}
              </MessageContent>
            </Message>
          ))}
          
          {isLoading && (
            <Message role="ai">
              <Avatar className="avatar">
                <Bot size={20} />
              </Avatar>
              <TypingIndicator>
                <TypingDot />
                <TypingDot />
                <TypingDot />
              </TypingIndicator>
            </Message>
          )}
        </ChatContainer>
        
        <QuickSuggestions>
          {quickSuggestions.map((suggestion, index) => (
            <SuggestionButton 
              key={index} 
              onClick={() => handleSuggestionClick(suggestion)}
            >
              {suggestion}
            </SuggestionButton>
          ))}
        </QuickSuggestions>
        
        <InputContainer>
          <InputWrapper>
            <Input
              ref={textareaRef}
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Message AI assistant... (Press Enter to send, Shift+Enter for new line)"
              disabled={isLoading}
            />
            <SendButton 
              onClick={handleSendMessage} 
              disabled={!inputValue.trim() || isLoading}
            >
              {isLoading ? <Loader size={20} /> : <Send size={20} />}
            </SendButton>
          </InputWrapper>
        </InputContainer>
      </MainContent>
    </Container>
  );
}

export default AIChat;
